```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace transaction_transfer_funds {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
};

bool transfer_funds(int from_account_id, int to_account_id, double amount) {
  // Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }
  auto conn = conn_result.value();

  // Begin transaction
  auto begin_result = conn->begin_transaction();
  if (!begin_result) {
    return false;
  }

  try {
    // Read from_account balance
    auto from_account_query = sqlgen::read<std::vector<Account>> 
                             | sqlgen::where(sqlgen::col<"account_id"> == from_account_id);
    auto from_account_result = from_account_query(*conn);
    if (!from_account_result) {
      conn->rollback();
      return false;
    }

    auto from_account = from_account_result.value();
    if (from_account.empty()) {
      conn->rollback();
      return false;
    }

    // Check sufficient funds
    if (from_account[0].balance < amount) {
      conn->rollback();
      return false;
    }

    // Update from_account: balance = balance - amount
    auto update_from = sqlgen::update<Account>(sqlgen::col<"balance">.set(sqlgen::col<"balance"> - amount))
                     | sqlgen::where(sqlgen::col<"account_id"> == from_account_id);
    auto update_from_result = update_from(*conn);
    if (!update_from_result) {
      conn->rollback();
      return false;
    }

    // Update to_account: balance = balance + amount
    auto update_to = sqlgen::update<Account>(sqlgen::col<"balance">.set(sqlgen::col<"balance"> + amount))
                     | sqlgen::where(sqlgen::col<"account_id"> == to_account_id);
    auto update_to_result = update_to(*conn);
    if (!update_to_result) {
      conn->rollback();
      return false;
    }

    // Commit transaction
    auto commit_result = conn->commit();
    if (!commit_result) {
      conn->rollback();
      return false;
    }

    return true;

  } catch (...) {
    // Rollback on any exception
    conn->rollback();
    return false;
  }
}

}  // namespace transaction_transfer_funds
```

## Key Implementation Points:

1. **Database Connection**: Uses `sqlgen::sqlite::connect()` to establish connection to "test_db.sqlite"

2. **Transaction Management**: 
   - Begins transaction with `conn->begin_transaction()`
   - Commits on success with `conn->commit()`
   - Rolls back on failure with `conn->rollback()`

3. **Query Construction**:
   - Uses `sqlgen::read<std::vector<Account>>` to query account balances
   - Applies `where` conditions using the pipe operator `|`
   - Uses column literals like `sqlgen::col<"account_id">` for field references

4. **Update Operations**:
   - Uses `sqlgen::update<Account>()` with `set()` operations
   - Implements arithmetic operations (`balance - amount`, `balance + amount`)
   - Applies conditional updates with `where` clauses

5. **Error Handling**:
   - Checks all operation results
   - Uses try-catch for exception safety
   - Ensures proper rollback on any failure

The implementation follows the exact SQL logic specified in the reference materials while leveraging sqlgen's fluent API for type-safe database operations.

