namespace analyze_social_network {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::string email;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> join_date;
  std::string city;
};

struct Friendship {
  int user_id1;
  int user_id2;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> friendship_date;
  sqlgen::PrimaryKey<std::tuple<int, int>> primary_key;
};

struct FriendConnection {
  std::string user1_name;
  std::string user2_name;
};

std::vector<FriendConnection> analyze_social_network_impl(const std::vector<User>& users, const std::vector<Friendship>& friendships) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // 1. Create database connection
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    std::cerr << "Failed to connect to database" << std::endl;
    return {};
  }
  auto conn = *conn_result;

  // 2. Create tables
  auto create_user_table = sqlgen::create_table<User>;
  auto create_friendship_table = sqlgen::create_table<Friendship>;

  create_user_table(conn);
  create_friendship_table(conn);

  // 3. Insert data
  auto write_users = sqlgen::write(users);
  auto write_friendships = sqlgen::write(friendships);

  write_users(conn);
  write_friendships(conn);

  // 4. Query 1: Mutual friends using SELF-JOIN
  auto mutual_friends_query = read<std::vector<FriendConnection>>
    | inner_join<User, "u1">("user_id"_t1 == "user_id1"_t2)
    | inner_join<Friendship, "f2">("user_id2"_t1 == "user_id1"_t3)
    | inner_join<User, "u2">("user_id2"_t2 == "user_id"_t4)
    | where("user_id"_t1 < "user_id"_t2)
    | exists(
        read<std::vector<Friendship>>
        | where("user_id1"_t5 == "user_id"_t1 && "user_id2"_t5 == "user_id"_t2)
      )
    | group_by("user_id"_t1, "user_id"_t2)
    | having(count() > 0)
    | to<std::vector<FriendConnection>>;

  auto mutual_friends = mutual_friends_query(conn);

  // 5. Query 2: Users with more than average friends
  auto avg_friends_query = read<std::vector<std::pair<int, int>>>
    | select_from<User, "u">(count("user_id2"_t1).as<"friend_count">)
    | group_by("user_id"_t1)
    | having(count() > 
        read<std::vector<double>>
        | select_from<User, "u">(avg(count("user_id2"_t1)))
        | group_by()
      );

  // 6. Query 3: Friend-of-friend relationships
  auto friend_of_friend_query = read<std::vector<FriendConnection>>
    | inner_join<Friendship, "f1">("user_id"_t1 == "user_id1"_t2)
    | inner_join<Friendship, "f2">("user_id2"_t2 == "user_id1"_t3)
    | inner_join<User, "u2">("user_id2"_t3 == "user_id"_t4)
    | where(!exists(
        read<std::vector<Friendship>>
        | where(("user_id1"_t5 == "user_id"_t1 && "user_id2"_t5 == "user_id"_t4) ||
                ("user_id1"_t5 == "user_id"_t4 && "user_id2"_t5 == "user_id"_t1))
      ));

  // 7. Query 4: Friends count per user
  auto friends_count_query = read<std::vector<std::pair<int, int>>>
    | select_from<User, "u">(count("user_id2"_t1).as<"friend_count">)
    | group_by("user_id"_t1);

  // 8. Query 5: Same city recommendations
  auto recommendations_query = read<std::vector<FriendConnection>>
    | inner_join<User, "u2">("city"_t1 == "city"_t2 && "user_id"_t1 < "user_id"_t2)
    | where(!exists(
        read<std::vector<Friendship>>
        | where(("user_id1"_t3 == "user_id"_t1 && "user_id2"_t3 == "user_id"_t2) ||
                ("user_id1"_t3 == "user_id"_t2 && "user_id2"_t3 == "user_id"_t1))
      ));

  // Return mutual friends as specified in the requirements
  return mutual_friends.value_or(std::vector<FriendConnection>{});
}

}  // namespace analyze_social_network
```

## Key Implementation Details:

1. **Database Connection**: Uses `sqlgen::sqlite::connect()` to establish connection to "test_db.sqlite"

2. **Table Creation**: Uses `sqlgen::create_table<T>` to create User and Friendship tables with proper schema

3. **Data Insertion**: Uses `sqlgen::write()` to insert the provided user and friendship data

4. **Mutual Friends Query**: Implements the SELF-JOIN query using:
   - Multiple `inner_join()` operations
