#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <map>
#include <algorithm>

namespace weekday_sales_analysis {

struct Sales {
  sqlgen::PrimaryKey<int> sale_id;
  int product_id;
  int quantity;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> sale_time;
};

struct WeekdayStats {
  int weekday;
  int total_quantity;
};

/**
 * Description: This function analyzes sales data to calculate total quantity sold for each weekday.
 * Returns: std::vector<WeekdayStats>.
 */
std::vector<WeekdayStats> weekday_sales_analysis() {
  // Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return {}; // Return empty vector on connection failure
  }
  auto conn = conn_result.value();

  // Read Sales data from database
  auto sales_result = sqlgen::read<std::vector<Sales>>(conn);
  if (!sales_result) {
    return {}; // Return empty vector on read failure
  }
  auto sales = sales_result.value();

  // Create a map to accumulate weekday totals
  std::map<int, int> weekday_totals;

  // Process each sale to extract weekday and accumulate quantities
  for (const auto& sale : sales) {
    // Extract weekday from sale_time (assuming weekday() returns 0=Sunday, 1=Monday, ..., 6=Saturday)
    int weekday = sale.sale_time.weekday();

    // Accumulate quantity for this weekday
    weekday_totals[weekday] += sale.quantity;
  }

  // Convert the map to a sorted vector of WeekdayStats
  std::vector<WeekdayStats> result;
  for (const auto& [weekday, total_quantity] : weekday_totals) {
    result.push_back({weekday, total_quantity});
  }

  // Sort by weekday number (optional, but makes output consistent)
  std::sort(result.begin(), result.end(), 
              [](const WeekdayStats& a, const WeekdayStats& b) {
                return a.weekday < b.weekday;
              });

  return result;
}

}  // namespace weekday_sales_analysis

